// App.js
import React, { useState } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate, Outlet } from 'react-router-dom';
import './globals.css';
import './public.css';
import './student.css';

// ─── PUBLIC PAGES ───
import Navbar from './components/Navbar';
import Home from './pages/Home';
import InternshipList from './pages/InternshipList';
import InternshipDetails from './pages/InternshipDetails';
import TrainingList from './pages/TrainingList';
import Login from './pages/Login';
import Register from './pages/Register';

// ─── STUDENT PAGES (Updated Paths to match your components folder!) ───
import StudentNavbar from './components/StudentNavbar';
import BrowseInternships from './components/BrowseInternships';
import MyApplications from './components/MyApplications';
import MyTrainings from './components/MyTrainings';
import StudentProfile from './components/StudentProfile';

export default function App() {
  const [user, setUser] = useState(null); 

  const handleLogin = (role) => {
    // role is either 'student' or 'employer'
    setUser({ role: role, name: 'Guest' });
  };

  const handleLogout = () => {
    setUser(null);
  };

  // ─── LAYOUT WRAPPERS ───
  const PublicLayout = () => {
    if (user && user.role === 'student') {
      return <Navigate to="/student/browse" replace />; // Redirect logged in student
    }
    // TEMPORARY: Prevent Employers from being stuck until their layout is ready
    if (user && user.role === 'employer') {
      alert("Employer dashboard coming soon!"); 
      return <Navigate to="/" replace />; 
    }

    return (
      <>
        <Navbar />
        <main style={{ paddingTop: 'var(--nav-height)' }}>
          <Outlet /> 
        </main>
      </>
    );
  };

  const StudentLayout = () => {
    if (!user || user.role !== 'student') {
      return <Navigate to="/login" replace />; // Redirect non-students to login
    }
    return (
      <div className="student-dashboard">
        <StudentNavbar logout={handleLogout} />
        <main className="dashboard-content" style={{ paddingTop: 'var(--nav-height)' }}>
          <Outlet />
        </main>
      </div>
    );
  };

  return (
    <Router>
      <Routes>

        {/* PUBLIC ROUTES */}
        <Route element={<PublicLayout />}>
          <Route path="/" element={<Home />} />
          <Route path="/internships" element={<InternshipList />} />
          <Route path="/internships/:id" element={<InternshipDetails />} />
          <Route path="/trainings" element={<TrainingList />} />

          <Route path="/login" element={<Login onLogin={handleLogin} />} />
          <Route path="/register" element={<Register onRegister={handleLogin} />} />
        </Route>

        {/* STUDENT ROUTES */}
        <Route path="/student" element={<StudentLayout />}>
          <Route path="browse" element={<BrowseInternships />} />
          <Route path="applications" element={<MyApplications />} />
          <Route path="trainings" element={<MyTrainings />} />
          <Route path="profile" element={<StudentProfile />} />
        </Route>

      </Routes>
    </Router>
  );
}
